/*
	Used to cache argument checks of interpolation functions.
	
	Caching pays off in particular for the multi-dimensionals encoding the
	interpolation table, since such are very likely never changing at all
	constants or only at recalibration changing parameters (Recalibrate() can
	take care of invalidating the cache for such). If an argument is a runtime
	variable computed by DoStep(), caching its check result must be turned off
	(such could be only cached if we can guarantee they are not changing
	inbetween interpolation calls which is very, very unlikely).
	
	All cached checks are combined into a single error signal; thus, if any
	single cached argument changes, the whole cache must be invalidated.
	
	Interpolation functions get the cache by pointer form their callsite
	(which therefore is responsible to invalidate it, if, for example, a
	parameter changes via recalibration), and, if it is invalid, update it
	with the newly computed check results. If NULL is passed, ALL argument
	checks are turned off, not only cached ones (hence, NULL does not only
	turn off caching, but checking in general; to turn off caching only,
	a cache with each invdividual argument cache turned off must be passed).
*/
typedef struct
{
	bool cache_is_valid;
	/* Arguments for which checks are cached: */
	bool cache_x1_data_check;
	bool cache_x2_data_check;
	bool cache_x3_data_check;
	bool cache_y_data_check;
	/* Cached errors: */
	SPE_ErrorSignal_Hcbd8c48e05b139646178cc6f7987b8955b6ce985_fba3e0dfa6c8985b41bcbe3594ee941ce98b740c error_signal;
} SPE_InterpolationCheckscache_Hcbd8c48e05b139646178cc6f7987b8955b6ce985_fba3e0dfa6c8985b41bcbe3594ee941ce98b740c;
